import React, { useState } from "react";
import "./FeaturedProducts.scss";
import Card from "../Card/Card";
import { useEffect } from "react";

const FeaturedProducts = ({ type }) => {
  const [meals, setMeals] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [httpError, setHttpError] = useState();

  useEffect(() => {
    const fetchMeals = async () => {
      const response = await fetch(
        "https://food-menu-app-aaa01-default-rtdb.firebaseio.com/meals.json"
      );

      if (!response.ok) {
        throw new Error("Something went wrong!");
      }

      const responseData = await response.json();

      const loadedMeals = [];

      for (const key in responseData) {
        loadedMeals.push({
          id: key,
          name: responseData[key].name,
          description: responseData[key].description,
          price: responseData[key].price,
        });
      }

      setMeals(loadedMeals);
      setIsLoading(false);
    };

    fetchMeals().catch((error) => {
      setIsLoading(false);
      setHttpError(error.message);
    });
  }, []);

  if (isLoading) {
    return (
      <section>
        <p>Fetching Data From Backend...</p>
      </section>
    );
  }

  if (httpError) {
    return (
      <section>
        <p>{httpError}</p>
      </section>
    );
  }

  const featuredDataList = meals.map((item) => (
    <Card item={item} key={item.id} />
  ));

  return (
    <div className="featuredProducts">
      <div className="top">
        <h1> {type} products</h1>
        <p>
          Lorem ipsum dolor sit amet consectetur adipisicing elit.
          Reprehenderit, eaque voluptatum. Repellat illo voluptas odio quidem
          velit laboriosam? Esse ullam laborum facere sed labore repellendus
          velit assumenda ad vitae impedit?
        </p>
      </div>
      <div className="bottom">{featuredDataList}</div>
    </div>
  );
};

export default FeaturedProducts;
